@using sv_2ece2a8f758c484ca7f77393df631e86.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnSelected" role="button">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-description">@Channel.Description</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnSelected { get; set; }
}

.channel-item {
    padding: 8px 12px;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.05);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.1);
    border-left-color: #5865f2;
}

.channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    color: #fff;
    font-size: 0.95rem;
}

.unread-badge {
    background-color: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.8rem;
    color: #8e9297;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

@using sv_2ece2a8f758c484ca7f77393df631e86.Services

<div class="message-item" @onmouseenter="() => _showActions = true" @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@GetRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="btn-thread-link" @onclick="OnOpenThread" @onclick:stopPropagation>
            💬 @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="btn-action" @onclick="OnOpenThread" title="Reply in thread">💬</button>
            <button class="btn-action" @onclick="ToggleEmojiPicker" title="Add reaction">😀</button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in CommonEmojis)
            {
                <button class="btn-emoji" @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    private static readonly string[] CommonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "👎"];

    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnAddReaction { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void OnMouseLeave()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        _showEmojiPicker = false;
        _showActions = false;
        await OnAddReaction.InvokeAsync(emoji);
    }

    private static string GetRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 30) return "just now";
        if (diff.TotalMinutes < 1) return $"{(int)diff.TotalSeconds}s ago";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
    position: relative;
    padding: 8px 16px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: rgba(0, 0, 0, 0.1);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    color: #fff;
}

.message-time {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    color: #dcddde;
    line-height: 1.4;
    word-wrap: break-word;
}

.reactions {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border-radius: 12px;
    background-color: rgba(88, 101, 242, 0.15);
    border: 1px solid rgba(88, 101, 242, 0.3);
    font-size: 0.85rem;
    color: #dcddde;
    cursor: default;
}

.btn-thread-link {
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    padding: 4px 0;
    cursor: pointer;
    font-weight: 600;
}

.btn-thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background-color: #2f3136;
    border: 1px solid #202225;
    border-radius: 4px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 5;
}

.btn-action {
    background: none;
    border: none;
    padding: 4px 8px;
    cursor: pointer;
    border-radius: 3px;
    font-size: 1rem;
    line-height: 1;
}

.btn-action:hover {
    background-color: rgba(255, 255, 255, 0.1);
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 90px;
    display: flex;
    gap: 2px;
    background-color: #2f3136;
    border: 1px solid #202225;
    border-radius: 4px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 10;
}

.btn-emoji {
    background: none;
    border: none;
    padding: 4px;
    cursor: pointer;
    font-size: 1.2rem;
    border-radius: 3px;
    line-height: 1;
}

.btn-emoji:hover {
    background-color: rgba(255, 255, 255, 0.1);
}

.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    background-color: #40444b;
    border-top: 1px solid #202225;
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    background-color: #40444b;
    border: 1px solid #202225;
    color: #dcddde;
    resize: none;
    border-radius: 8px;
    padding: 8px 12px;
}

.message-textarea:focus {
    background-color: #40444b;
    color: #dcddde;
    border-color: #5865f2;
    box-shadow: none;
}

.message-textarea::placeholder {
    color: #72767d;
}

.send-btn {
    background-color: #5865f2;
    border-color: #5865f2;
    padding: 8px 20px;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background-color: #4752c4;
    border-color: #4752c4;
}

.send-btn:disabled {
    background-color: #5865f2;
    border-color: #5865f2;
    opacity: 0.5;
}

export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function getScrollHeight(element) {
    return element ? element.scrollHeight : 0;
}

export function restoreScrollPosition(element, previousScrollHeight) {
    if (element) {
        element.scrollTop = element.scrollHeight - previousScrollHeight;
    }
}

