toolArgs.file_text:
.message-item {
    position: relative;
    padding: 8px 16px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: rgba(0, 0, 0, 0.1);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    color: #fff;
}

.message-time {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    color: #dcddde;
    line-height: 1.4;
    word-wrap: break-word;
}

.reactions {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border-radius: 12px;
    background-color: rgba(88, 101, 242, 0.15);
    border: 1px solid rgba(88, 101, 242, 0.3);
    font-size: 0.85rem;
    color: #dcddde;
    cursor: default;
}

.btn-thread-link {
    background: none;
    border: none;
    color: #00aff4;
    font-size: 0.8rem;
    padding: 4px 0;
    cursor: pointer;
    font-weight: 600;
}

.btn-thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background-color: #2f3136;
    border: 1px solid #202225;
    border-radius: 4px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 5;
}

.btn-action {
    background: none;
    border: none;
    padding: 4px 8px;
    cursor: pointer;
    border-radius: 3px;
    font-size: 1rem;
    line-height: 1;
}

.btn-action:hover {
    background-color: rgba(255, 255, 255, 0.1);
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 90px;
    display: flex;
    gap: 2px;
    background-color: #2f3136;
    border: 1px solid #202225;
    border-radius: 4px;
    padding: 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 10;
}

.btn-emoji {
    background: none;
    border: none;
    padding: 4px;
    cursor: pointer;
    font-size: 1.2rem;
    border-radius: 3px;
    line-height: 1;
}

.btn-emoji:hover {
    background-color: rgba(255, 255, 255, 0.1);
}

