@using sv_2ece2a8f758c484ca7f77393df631e86.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h6>CHANNELS</h6>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    background-color: #2f3136;
    height: 100%;
    overflow: hidden;
}

.sidebar-header {
    padding: 14px 16px;
    border-bottom: 1px solid #202225;
}

.sidebar-header h6 {
    margin: 0;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    color: #8e9297;
    font-weight: 700;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

@using sv_2ece2a8f758c484ca7f77393df631e86.Services
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-area">
    <div class="area-header">
        @if (CurrentChannel is not null)
        {
            <h5># @CurrentChannel.Name</h5>
            <span class="header-description">@CurrentChannel.Description</span>
        }
    </div>

    <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
        @if (HasMore)
        {
            <div class="load-more-area">
                @if (IsLoadingMore)
                {
                    <span class="loading-indicator">Loading older messages…</span>
                }
                else
                {
                    <button class="btn btn-sm btn-load-more" @onclick="LoadMore">
                        ↑ Load older messages
                    </button>
                }
            </div>
        }

        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ReplyCount="GetReplyCount(message.Id)"
                         OnOpenThread="() => OnOpenThread.InvokeAsync(message.Id)"
                         OnAddReaction="(emoji) => OnAddReaction.InvokeAsync((message.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{CurrentChannel?.Name ?? "channel"}")"
                  ButtonText="Send"
                  OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter] public Channel? CurrentChannel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ReplyCounts { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnAddReaction { get; set; }

    private ElementReference _messageListRef;
    private IJSObjectReference? _jsModule;
    private bool _shouldScrollToBottom = true;
    private int? _previousChannelId;

    private int GetReplyCount(int messageId) =>
        ReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _jsModule = await JS.InvokeAsync<IJSObjectReference>("import", "./js/chat.js");
        }

        if (_shouldScrollToBottom && _jsModule is not null)
        {
            await _jsModule.InvokeVoidAsync("scrollToBottom", _messageListRef);
            _shouldScrollToBottom = false;
        }
    }

    protected override void OnParametersSet()
    {
        if (CurrentChannel?.Id != _previousChannelId)
        {
            _shouldScrollToBottom = true;
            _previousChannelId = CurrentChannel?.Id;
        }
    }

    private void HandleScroll()
    {
        // Scroll event is raised; actual scroll-to-top detection
        // could use JS interop for precise position tracking.
        // The "Load older messages" button provides the primary UX.
    }

    private async Task LoadMore()
    {
        double previousScrollHeight = 0;
        if (_jsModule is not null)
        {
            previousScrollHeight = await _jsModule.InvokeAsync<double>("getScrollHeight", _messageListRef);
        }

        await OnLoadMore.InvokeAsync();

        // Restore scroll position so new messages don't jump the view
        if (_jsModule is not null && previousScrollHeight > 0)
        {
            await Task.Yield();
            await _jsModule.InvokeVoidAsync("restoreScrollPosition", _messageListRef, previousScrollHeight);
        }
    }

    public void ScrollToBottom() => _shouldScrollToBottom = true;

    public async ValueTask DisposeAsync()
    {
        if (_jsModule is not null)
        {
            await _jsModule.DisposeAsync();
        }
    }
}

.message-area {
