toolArgs.file_text:
@using sv_2ece2a8f758c484ca7f77393df631e86.Services

<div class="thread-panel @(IsOpen ? "open" : "")">
    @if (IsOpen && RootMessage is not null)
    {
        <div class="thread-header">
            <h6>Thread</h6>
            <button class="btn-close-thread" @onclick="OnClose" title="Close thread">✕</button>
        </div>

        <div class="thread-root-quote">
            <div class="quote-author">@RootMessage.Author</div>
            <div class="quote-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <MessageItem Message="reply"
                             ReplyCount="0"
                             OnAddReaction="(emoji) => OnAddReplyReaction.InvokeAsync((reply.Id, emoji))" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread..."
                      ButtonText="Reply"
                      OnSubmit="OnSendReply" />
    }
</div>

@code {
    [Parameter] public bool IsOpen { get; set; }
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnAddReplyReaction { get; set; }
}

.thread-panel {
    display: none;
    flex-direction: column;
    background-color: #36393f;
    border-left: 1px solid #202225;
    height: 100%;
    overflow: hidden;
}

.thread-panel.open {
    display: flex;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #202225;
    flex-shrink: 0;
}

.thread-header h6 {
    margin: 0;
    color: #fff;
    font-weight: 700;
    font-size: 1rem;
}

.btn-close-thread {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 3px;
    line-height: 1;
}

.btn-close-thread:hover {
    background-color: rgba(255, 255, 255, 0.1);
    color: #fff;
}

.thread-root-quote {
    padding: 12px 16px;
    background-color: rgba(0, 0, 0, 0.1);
    border-left: 3px solid #5865f2;
    margin: 12px 16px 0;
    border-radius: 0 4px 4px 0;
}

.quote-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.9rem;
    margin-bottom: 4px;
}

.quote-content {
    color: #b9bbbe;
    font-size: 0.85rem;
    line-height: 1.4;
}

.thread-divider {
    display: flex;
    align-items: center;
    padding: 8px 16px;
    gap: 8px;
}

.thread-divider::before,
.thread-divider::after {
    content: "";
    flex: 1;
    height: 1px;
    background-color: #4f545c;
}

.thread-divider span {
    color: #72767d;
    font-size: 0.75rem;
    white-space: nowrap;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

