arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer

@using sv_2ece2a8f758c484ca7f77393df631e86.Components.Layout
@using sv_2ece2a8f758c484ca7f77393df631e86.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="panel-sidebar">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="panel-main @(_isThreadOpen ? "" : "expanded")">
        <MessageArea @ref="_messageArea"
                     CurrentChannel="_currentChannel"
                     Messages="_messages"
                     ReplyCounts="_replyCounts"
                     HasMore="_hasMore"
                     IsLoadingMore="_isLoadingMore"
                     OnLoadMore="LoadMoreMessages"
                     OnSendMessage="SendMessage"
                     OnOpenThread="OpenThread"
                     OnAddReaction="AddReaction" />
    </div>

    <div class="panel-thread @(_isThreadOpen ? "open" : "")">
        <ThreadPanel IsOpen="_isThreadOpen"
                     RootMessage="_threadRootMessage"
                     Replies="_threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply"
                     OnAddReplyReaction="AddReaction" />
    </div>
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private Dictionary<int, int> _replyCounts = [];

    private int? _selectedChannelId;
    private Channel? _currentChannel;
    private bool _hasMore;
    private bool _isLoadingMore;
    private int _messageSkip;

    private bool _isThreadOpen;
    private int? _threadRootId;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    private MessageArea? _messageArea;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        if (_selectedChannelId == channelId) return;

        _selectedChannelId = channelId;
        _currentChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messageSkip = 0;
        _messages = [];
        _replyCounts = [];
        CloseThread();

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _messageSkip = messages.Count;
        _hasMore = messages.Count == PageSize;

        BuildReplyCounts();
        await ChatService.MarkChannelReadAsync(channelId);

        // Update unread count locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore || _selectedChannelId is null) return;

        _isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_selectedChannelId.Value, _messageSkip, PageSize);
        _messages.InsertRange(0, older);
        _messageSkip += older.Count;
        _hasMore = older.Count == PageSize;
        _isLoadingMore = false;

        BuildReplyCounts();
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannelId is null) return;

        var message = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
        _messages.Add(message);
        _messageArea?.ScrollToBottom();
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootId = rootMessageId;
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _isThreadOpen = true;
    }

    private void CloseThread()
    {
        _isThreadOpen = false;
        _threadRootId = null;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_selectedChannelId is null || _threadRootId is null) return;

        var reply = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, _threadRootId);
        _threadReplies.Add(reply);

        // Update reply count
        _replyCounts[_threadRootId.Value] = _threadReplies.Count;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the reaction in the local message list
        UpdateReactionLocally(_messages, args.MessageId, args.Emoji);
        UpdateReactionLocally(_threadReplies, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionLocally(List<Message> messages, int messageId, string emoji)
    {
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
            {
                existing.Users.Add("You");
            }
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private void BuildReplyCounts()
    {
        _replyCounts = [];
        foreach (var msg in _messages)
        {
            if (msg.ReplyToId is int rootId)
            {
                _replyCounts[rootId] = _replyCounts.GetValueOrDefault(rootId) + 1;
            }
        }
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
}

.panel-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.panel-main {
    flex: 55;
    min-width: 0;
    transition: flex 0.2s ease;
}

.panel-main.expanded {
    flex: 80;
}

.panel-thread {
    width: 0;
    flex-shrink: 0;
    overflow: hidden;
    transition: width 0.2s ease;
}

.panel-thread.open {
    width: 25%;
    min-width: 300px;
    max-width: 420px;
}

