+        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
+        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
+        _isThreadOpen = true;
+    }
+
+    private void CloseThread()
+    {
+        _isThreadOpen = false;
+        _threadRootId = null;
+        _threadRootMessage = null;
+        _threadReplies = [];
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (_selectedChannelId is null || _threadRootId is null) return;
+
+        var reply = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, _threadRootId);
+        _threadReplies.Add(reply);
+
+        // Update reply count
+        _replyCounts[_threadRootId.Value] = _threadReplies.Count;
+    }
+
+    private async Task AddReaction((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+
+        // Optimistically update the reaction in the local message list
+        UpdateReactionLocally(_messages, args.MessageId, args.Emoji);
+        UpdateReactionLocally(_threadReplies, args.MessageId, args.Emoji);
+    }
+
+    private static void UpdateReactionLocally(List<Message> messages, int messageId, string emoji)
+    {
+        var idx = messages.FindIndex(m => m.Id == messageId);
+        if (idx < 0) return;
+
+        var msg = messages[idx];
+        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
+        if (existing is not null)
+        {
+            if (!existing.Users.Contains("You"))
+            {
+                existing.Users.Add("You");
+            }
+        }
+        else
+        {
+            msg.Reactions.Add(new Reaction(emoji, ["You"]));
+        }
+    }
+
+    private void BuildReplyCounts()
+    {
+        _replyCounts = [];
+        foreach (var msg in _messages)
+        {
+            if (msg.ReplyToId is int rootId)
+            {
+                _replyCounts[rootId] = _replyCounts.GetValueOrDefault(rootId) + 1;
+            }
+        }
+    }
+}
+

